/// A [GPOS Extension Positioning](https://learn.microsoft.com/en-us/typography/opentype/spec/gpos#lookuptype-9-extension-positioning) subtable
pub enum ExtensionSubtable<'a> {
    Single(ExtensionPosFormat1<'a, SinglePos<'a>>),
    Pair(ExtensionPosFormat1<'a, PairPos<'a>>),
    Cursive(ExtensionPosFormat1<'a, CursivePosFormat1<'a>>),
    MarkToBase(ExtensionPosFormat1<'a, MarkBasePosFormat1<'a>>),
    MarkToLig(ExtensionPosFormat1<'a, MarkLigPosFormat1<'a>>),
    MarkToMark(ExtensionPosFormat1<'a, MarkMarkPosFormat1<'a>>),
    Contextual(ExtensionPosFormat1<'a, PositionSequenceContext<'a>>),
    ChainContextual(ExtensionPosFormat1<'a, PositionChainContext<'a>>),
}

impl Default for ExtensionSubtable<'_> {
    fn default() -> Self {
        Self::Single(Default::default())
    }
}

impl ReadArgs for ExtensionSubtable<'_> {
    type Args = ();
}

impl<'a> FontRead<'a> for ExtensionSubtable<'a> {
    fn read_with_args(bytes: FontData<'a>, _: ()) -> Result<Self, ReadError> {
        let discriminant = ExtensionPosFormat1::read_discriminant(bytes)?;
        match discriminant {
            1 => Ok(ExtensionSubtable::Single(FontRead::read(bytes)?)),
            2 => Ok(ExtensionSubtable::Pair(FontRead::read(bytes)?)),
            3 => Ok(ExtensionSubtable::Cursive(FontRead::read(bytes)?)),
            4 => Ok(ExtensionSubtable::MarkToBase(FontRead::read(bytes)?)),
            5 => Ok(ExtensionSubtable::MarkToLig(FontRead::read(bytes)?)),
            6 => Ok(ExtensionSubtable::MarkToMark(FontRead::read(bytes)?)),
            7 => Ok(ExtensionSubtable::Contextual(FontRead::read(bytes)?)),
            8 => Ok(ExtensionSubtable::ChainContextual(FontRead::read(bytes)?)),
            other => Err(ReadError::InvalidFormat(other.into())),
        }
    }
}

impl<'a> ExtensionSubtable<'a> {
    #[allow(dead_code)]
    /// Return the inner table, removing the specific generics.
    ///
    /// This lets us return a single concrete type we can call methods on.
    pub(crate) fn of_unit_type(&self) -> ExtensionPosFormat1<'a, ()> {
        match self {
            ExtensionSubtable::Single(inner) => inner.of_unit_type(),
            ExtensionSubtable::Pair(inner) => inner.of_unit_type(),
            ExtensionSubtable::Cursive(inner) => inner.of_unit_type(),
            ExtensionSubtable::MarkToBase(inner) => inner.of_unit_type(),
            ExtensionSubtable::MarkToLig(inner) => inner.of_unit_type(),
            ExtensionSubtable::MarkToMark(inner) => inner.of_unit_type(),
            ExtensionSubtable::Contextual(inner) => inner.of_unit_type(),
            ExtensionSubtable::ChainContextual(inner) => inner.of_unit_type(),
        }
    }
}

impl<'a> Sanitize<'a> for ExtensionSubtable<'a> {
    fn sanitize(ctx: &mut SanitizeContext<'a, '_>, _args: ()) -> Result<(), ReadError> {
        let discriminant = ExtensionPosFormat1::read_discriminant(ctx.data())?;
        match discriminant {
            1 => ExtensionPosFormat1::<SinglePos>::sanitize(ctx, _args),
            2 => ExtensionPosFormat1::<PairPos>::sanitize(ctx, _args),
            3 => ExtensionPosFormat1::<CursivePosFormat1>::sanitize(ctx, _args),
            4 => ExtensionPosFormat1::<MarkBasePosFormat1>::sanitize(ctx, _args),
            5 => ExtensionPosFormat1::<MarkLigPosFormat1>::sanitize(ctx, _args),
            6 => ExtensionPosFormat1::<MarkMarkPosFormat1>::sanitize(ctx, _args),
            7 => ExtensionPosFormat1::<PositionSequenceContext>::sanitize(ctx, _args),
            8 => ExtensionPosFormat1::<PositionChainContext>::sanitize(ctx, _args),
            other => Err(ReadError::InvalidFormat(other as _)),
        }
    }
    fn read_fast(data: FontData<'a>, _args: ()) -> Self {
        match ExtensionPosFormat1::read_discriminant(data) {
            Ok(1) => {
                ExtensionSubtable::Single(ExtensionPosFormat1::<SinglePos>::read_fast(data, ()))
            }
            Ok(2) => ExtensionSubtable::Pair(ExtensionPosFormat1::<PairPos>::read_fast(data, ())),
            Ok(3) => ExtensionSubtable::Cursive(
                ExtensionPosFormat1::<CursivePosFormat1>::read_fast(data, ()),
            ),
            Ok(4) => ExtensionSubtable::MarkToBase(
                ExtensionPosFormat1::<MarkBasePosFormat1>::read_fast(data, ()),
            ),
            Ok(5) => ExtensionSubtable::MarkToLig(
                ExtensionPosFormat1::<MarkLigPosFormat1>::read_fast(data, ()),
            ),
            Ok(6) => ExtensionSubtable::MarkToMark(
                ExtensionPosFormat1::<MarkMarkPosFormat1>::read_fast(data, ()),
            ),
            Ok(7) => ExtensionSubtable::Contextual(
                ExtensionPosFormat1::<PositionSequenceContext>::read_fast(data, ()),
            ),
            Ok(8) => ExtensionSubtable::ChainContextual(
                ExtensionPosFormat1::<PositionChainContext>::read_fast(data, ()),
            ),
            _ => ExtensionSubtable::default(),
        }
    }
}

